export function createSearchInput({ placeholder = 'Search lessons, references, projects…', onSearch, id = 'global-search' }) {
  const wrap = document.createElement('div');
  wrap.className = 'search-input';

  wrap.innerHTML = `
    <svg class="search-input__icon" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor" aria-hidden="true">
      <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"/>
    </svg>
  `;

  const input = document.createElement('input');
  input.type = 'search';
  input.id = id;
  input.className = 'form-input search-input__field';
  input.placeholder = placeholder;
  input.setAttribute('aria-label', placeholder);
  input.autocomplete = 'off';

  input.addEventListener('keydown', (e) => {
    if (e.key === 'Enter' && input.value.trim()) {
      window.location.hash = `#/search?q=${encodeURIComponent(input.value.trim())}`;
    }
  });

  if (onSearch) {
    input.addEventListener('input', () => onSearch(input.value));
  }

  wrap.appendChild(input);
  return wrap;
}

